class TestSpyOverboughtEntryBlock(unittest.TestCase):
    def test_blocks_when_spy_rsi_above_70(self):
        stats = {"rsi_snapshot": {"SPY": {"today": 71.5}}}
        fired, reason = heuristic_spy_overbought_entry_block(stats)
        self.assertTrue(fired)
        self.assertIn("71.5", reason)
    def test_no_block_at_neutral_rsi(self):
        stats = {"rsi_snapshot": {"SPY": {"today": 60.0}}}
        fired, _ = heuristic_spy_overbought_entry_block(stats)
        self.assertFalse(fired)
    def test_boundary_exactly_70_not_blocked(self):
        stats = {"rsi_snapshot": {"SPY": {"today": 70.0}}}
        fired, _ = heuristic_spy_overbought_entry_block(stats)
        self.assertFalse(fired)
    def test_handles_missing_spy_data_gracefully(self):
        fired, _ = heuristic_spy_overbought_entry_block({})
        self.assertFalse(fired)
